const now = new Date();
const taipei = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Taipei' }));
const hour = taipei.getHours();

let edition = 'morning';
let editionLabel = '早報';
let editionTime = '07:00';

if (hour >= 18) {
  edition = 'evening';
  editionLabel = '晚報';
  editionTime = '18:00';
} else if (hour >= 12) {
  edition = 'noon';
  editionLabel = '午報';
  editionTime = '12:00';
}

const dateStr = [
  taipei.getFullYear(),
  String(taipei.getMonth() + 1).padStart(2, '0'),
  String(taipei.getDate()).padStart(2, '0')
].join('-');

const dateLabel = taipei.toLocaleDateString('zh-TW', {
  timeZone: 'Asia/Taipei',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  weekday: 'long'
});

return [{
  json: {
    edition,
    editionLabel,
    editionTime,
    dateStr,
    dateLabel
  }
}];

const response = $input.first().json;
const edition = $('Set Edition').first().json;

const fallback = {
  headlines: [
    {
      id: 1,
      category: '科技',
      headline: 'AI 新聞資料暫時無法解析',
      summary: 'Gemini API 已回應，但內容未能成功轉成指定的 JSON 格式，請檢查提示詞或 API 回傳內容。',
      source_name: 'System Fallback',
      source_url: '#',
      published_time: '即時',
      importance: 1
    }
  ],
  deep_dive: []
};

function normalizeCategory(value) {
  if (value === '科技' || value === '財經' || value === '台股') return value;
  if (!value) return '科技';
  const text = String(value);
  if (text.includes('股')) return '台股';
  if (text.includes('財') || text.includes('經')) return '財經';
  return '科技';
}

let newsData = fallback;

try {
  const candidates = response.candidates || [];
  if (!candidates.length) throw new Error('No candidates');

  const parts = candidates[0].content?.parts || [];
  let text = parts.map((part) => part.text || '').join('').trim();
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  const parsed = JSON.parse(text);
  const headlines = Array.isArray(parsed.headlines) ? parsed.headlines : [];
  const deepDive = Array.isArray(parsed.deep_dive) ? parsed.deep_dive : [];

  newsData = {
    headlines: headlines.map((item, index) => ({
      id: index + 1,
      category: normalizeCategory(item.category),
      headline: String(item.headline || '').trim(),
      summary: String(item.summary || '').trim(),
      source_name: String(item.source_name || '').trim(),
      source_url: String(item.source_url || '#').trim() || '#',
      published_time: String(item.published_time || '').trim(),
      importance: Number(item.importance || index + 1)
    })).filter((item) => item.headline),
    deep_dive: deepDive.map((item, index) => ({
      id: index + 1,
      category: normalizeCategory(item.category),
      title: String(item.title || '').trim(),
      analysis: String(item.analysis || '').trim(),
      source_name: String(item.source_name || '').trim(),
      source_url: String(item.source_url || '#').trim() || '#'
    })).filter((item) => item.title)
  };

  if (!newsData.headlines.length) newsData = fallback;
} catch (error) {
  newsData = fallback;
}

const techNews = newsData.headlines.filter((item) => item.category === '科技');
const financeNews = newsData.headlines.filter((item) => item.category === '財經');
const stockNews = newsData.headlines.filter((item) => item.category === '台股');

return [{
  json: {
    ...edition,
    newsData,
    techNews,
    financeNews,
    stockNews
  }
}];

const data = $input.first().json;
const { edition, editionLabel, editionTime, dateStr, dateLabel, newsData } = data;

function escapeHtml(value = '') {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function tagClass(category) {
  if (category === '財經') return 'tag-finance';
  if (category === '台股') return 'tag-stock';
  return 'tag-tech';
}

const headlineCards = (newsData.headlines || []).map((item, index) => `
  <article class="card">
    <div class="card-number">${String(index + 1).padStart(2, '0')}</div>
    <span class="card-tag ${tagClass(item.category)}">${escapeHtml(item.category)}</span>
    <h2 class="card-headline">${escapeHtml(item.headline)}</h2>
    <p class="card-summary">${escapeHtml(item.summary)}</p>
    <div class="card-meta">
      <a href="${escapeHtml(item.source_url)}" target="_blank" rel="noopener">${escapeHtml(item.source_name)}</a>
      <span>${escapeHtml(item.published_time)}</span>
    </div>
  </article>
`).join('');

const deepCards = (newsData.deep_dive || []).map((item, index) => `
  <article class="deep-card">
    <div class="deep-number">${String(index + 1).padStart(2, '0')}</div>
    <div class="deep-label">${escapeHtml(item.category)}</div>
    <h3 class="deep-title">${escapeHtml(item.title)}</h3>
    <p class="deep-body">${escapeHtml(item.analysis)}</p>
    <a class="deep-source" href="${escapeHtml(item.source_url)}" target="_blank" rel="noopener">來源：${escapeHtml(item.source_name)}</a>
  </article>
`).join('');

const archiveFilename = `archive/${dateStr}-${edition}.html`;
const archiveHtml = `<!DOCTYPE html>
