</style>
</head>
<body>
<header class="header">
  <div class="header-inner">
    <a class="logo" href="../index.html">燈<span>塔</span>財經</a>
    <a class="back-link" href="../index.html">返回首頁</a>
  </div>
</header>
<section class="hero">
  <div class="content">
    <div class="meta">${escapeHtml(dateStr)} · ${escapeHtml(editionLabel)} · ${escapeHtml(editionTime)}</div>
