return [{
  json: {
    ...data,
    archiveFilename,
    archiveHtml
  }
}];

const archiveResponse = $input.first().json;
const data = $('Build Archive HTML').first().json;

let archiveList = [];
let archiveListSha = null;

try {
  if (archiveResponse.content) {
    archiveList = JSON.parse(Buffer.from(archiveResponse.content, 'base64').toString('utf8'));
    archiveListSha = archiveResponse.sha || null;
  }
} catch (error) {
  archiveList = [];
}

const newEntry = {
  date: data.dateStr,
  edition: data.edition,
  editionLabel: data.editionLabel,
  editionTime: data.editionTime,
  dateLabel: data.dateLabel,
  file: data.archiveFilename
};

archiveList = archiveList.filter((item) => !(item.date === newEntry.date && item.edition === newEntry.edition));
archiveList.unshift(newEntry);
archiveList = archiveList.slice(0, 90);

return [{
  json: {
    ...data,
    archiveList,
    archiveListSha
  }
}];

const data = $('Update Archive List').first().json;
const newsDataSha = $('Get News Data SHA').first().json.sha || null;
const archivePageSha = $('Get Archive Page SHA').first().json.sha || null;

function toBase64(value) {
  return Buffer.from(value, 'utf8').toString('base64');
}

const newsDataPayload = {
  edition: data.edition,
  editionLabel: data.editionLabel,
  editionTime: data.editionTime,
  dateStr: data.dateStr,
  dateLabel: data.dateLabel,
  newsData: data.newsData,
  techNews: data.techNews,
  financeNews: data.financeNews,
  stockNews: data.stockNews,
  archiveList: data.archiveList
};

return [
  {
    json: {
      path: 'news-data.json',
      content: toBase64(JSON.stringify(newsDataPayload, null, 2)),
      sha: newsDataSha,
      message: `[${data.editionLabel}] ${data.dateStr} ${data.editionTime} 更新新聞資料`
    }
  },
  {
    json: {
      path: 'archive-list.json',
      content: toBase64(JSON.stringify(data.archiveList, null, 2)),
      sha: data.archiveListSha,
      message: `${data.dateStr} 更新 archive-list`
    }
  },
  {
    json: {
      path: data.archiveFilename,
      content: toBase64(data.archiveHtml),
      sha: archivePageSha,
      message: `${data.dateStr} ${data.editionLabel} 新增封存頁`
    }
  }
];
